import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { logout } from '../../store/slices/authSlice';
import { toggleDarkMode, setComfortRoom } from '../../store/slices/uiSlice';
import { FiSun, FiMoon, FiLogOut, FiChevronDown, FiChevronRight } from 'react-icons/fi';

const NAV_SECTIONS = [
    {
        label: 'Core',
        items: [
            { path: '/dashboard', icon: '🏠', label: 'Home' },
            { path: '/mood', icon: '😊', label: 'Mood Tracker' },
            { path: '/journal', icon: '📓', label: 'Journal' },
            { path: '/companion', icon: '🤗', label: 'SAATHI AI' },
        ]
    },
    {
        label: 'Growth',
        items: [
            { path: '/habits', icon: '⚡', label: 'Habits' },
            { path: '/goals', icon: '🎯', label: 'Goals' },
            { path: '/rpg', icon: '⚔️', label: 'Life RPG' },
            { path: '/journey', icon: '📖', label: 'Life Journey' },
        ]
    },
    {
        label: 'Self-Discovery',
        items: [
            { path: '/personality', icon: '🧠', label: 'Personality' },
            { path: '/purpose', icon: '🧭', label: 'Purpose Discovery' },
            { path: '/career', icon: '🚀', label: 'Career Guidance' },
        ]
    },
    {
        label: 'World',
        items: [
            { path: '/island', icon: '🏝️', label: 'Personal Island' },
            { path: '/connection', icon: '❤️', label: 'Connection Score' },
            { path: '/shorts', icon: '✨', label: 'SAATHI Shorts' },
            { path: '/surprise', icon: '🎁', label: 'Daily Surprise' },
        ]
    },
    {
        label: 'Wisdom',
        items: [
            { path: '/life-library', icon: '📚', label: 'Life Library' },
            { path: '/hope-library', icon: '🌟', label: 'Hope Library' },
            { path: '/experts', icon: '🎓', label: 'Expert Creators' },
        ]
    },
    {
        label: 'Wellbeing',
        items: [
            { path: '/family', icon: '❤️', label: 'Family Hub' },
            { path: '/gratitude', icon: '🌱', label: 'Gratitude Garden' },
            { path: '/pet', icon: '🐾', label: 'Virtual Pet' },
            { path: '/dreams', icon: '🏰', label: 'Dream Tower' },
        ]
    },
    {
        label: 'Safe Space',
        items: [
            { path: '/vault', icon: '💜', label: 'Reasons to Live' },
            { path: '/inner-circle', icon: '❤️', label: 'Inner Circle' },
            { path: '/stress-game', icon: '💥', label: 'Stress Destroyer' },
        ]
    },
    {
        label: 'Community',
        items: [
            { path: '/community', icon: '🌍', label: 'Community' },
            { path: '/ask', icon: '🙈', label: 'Anonymous Ask' },
            { path: '/dream-communities', icon: '🌍', label: 'Dream Communities' },
            { path: '/focus', icon: '🌳', label: 'Focus Forest' },
        ]
    },
    {
        label: 'Calm Corner',
        items: [
            { path: '/coloring', icon: '🎨', label: 'Calm Coloring' },
            { path: '/relax', icon: '🎵', label: 'Relaxation Hub' },
            { path: '/memories', icon: '😊', label: 'Positive Memories' },
            { path: '/life-map', icon: '🗺️', label: 'Life Map' },
            { path: '/wellness', icon: '🌿', label: 'Wellness' },
        ]
    },
    {
        label: 'Account',
        items: [
            { path: '/notifications', icon: '🔔', label: 'Notifications' },
            { path: '/detox', icon: '🌿', label: 'Digital Detox' },
            { path: '/ai', icon: '🤖', label: 'AI Insights' },
            { path: '/offline', icon: '🔄', label: 'Offline & Sync' },
            { path: '/admin', icon: '⚙️', label: 'Admin Panel' },
        ]
    },
];

export default function Sidebar() {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const { user } = useSelector(s => s.auth);
    const { darkMode } = useSelector(s => s.ui);

    // Defaulting 'Core' to open, keeping the rest collapsed to avoid long vertical scrolls
    const [openSections, setOpenSections] = useState({ Core: true });

    const toggleSection = (label) => {
        setOpenSections(prev => ({
            ...prev,
            [label]: !prev[label]
        }));
    };

    const handleLogout = () => {
        dispatch(logout());
        navigate('/login');
    };

    return (
        <aside style={{
            width: 240, height: '100vh', position: 'fixed', left: 0, top: 0,
            background: 'white', borderRight: '1px solid var(--border)',
            display: 'flex', flexDirection: 'column', zIndex: 100,
            boxShadow: '2px 0 12px rgba(0,0,0,0.04)'
        }}>
            {/* Logo Section */}
            <div style={{ padding: '18px 20px 14px', borderBottom: '1px solid var(--border)', flexShrink: 0 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <div style={{
                        width: 34, height: 34, borderRadius: 10,
                        background: 'linear-gradient(135deg,#7c3aed,#a78bfa)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        color: 'white', fontWeight: 700, fontFamily: 'Poppins', fontSize: 15
                    }}>S</div>
                    <span style={{ fontFamily: 'Poppins', fontWeight: 700, fontSize: 19, color: '#7c3aed' }}>SAATHI</span>
                </div>
                {user && (
                    <p style={{ marginTop: 10, fontSize: 12, color: 'var(--text-secondary)' }}>
                        👋 <strong style={{ color: 'var(--text-primary)' }}>{user.fullName?.split(' ')[0]}</strong>
                        {' '}· Lvl {user.level || 1} · ⭐{user.xpPoints || 0}
                    </p>
                )}
            </div>

            {/* SOS Support Button */}
            <div style={{ padding: '10px 14px', flexShrink: 0 }}>
                <button onClick={() => dispatch(setComfortRoom(true))} style={{
                    width: '100%', padding: '8px 12px', borderRadius: 10,
                    background: 'linear-gradient(135deg,#fef2f2,#fff7ed)',
                    border: '1px solid #fecdd3', color: '#e11d48',
                    fontWeight: 600, fontSize: 12, cursor: 'pointer',
                    display: 'flex', alignItems: 'center', gap: 6
                }}>
                    <span>🫂</span> I Need Support
                </button>
            </div>

            {/* Navigation Links Accordion */}
            <nav style={{ flex: 1, overflowY: 'auto', padding: '4px 10px', scrollbarWidth: 'thin' }}>
                {NAV_SECTIONS.map(section => {
                    const isOpen = !!openSections[section.label];
                    return (
                        <div key={section.label} style={{ marginBottom: 4 }}>

                            {/* Collapsible Header Button */}
                            <button
                                onClick={() => toggleSection(section.label)}
                                style={{
                                    width: '100%', display: 'flex', alignItems: 'center',
                                    justifyContent: 'space-between', padding: '6px 10px',
                                    borderRadius: 8, border: 'none',
                                    background: isOpen ? '#f5f3ff' : 'transparent',
                                    cursor: 'pointer', marginBottom: 2,
                                    transition: 'background 0.15s'
                                }}
                                onMouseEnter={e => { if (!isOpen) e.currentTarget.style.background = '#fafafa'; }}
                                onMouseLeave={e => { if (!isOpen) e.currentTarget.style.background = 'transparent'; }}
                            >
                <span style={{
                    fontSize: 10, fontWeight: 700, letterSpacing: 1,
                    color: isOpen ? '#7c3aed' : 'var(--text-muted)',
                    textTransform: 'uppercase',
                }}>
                  {section.label}
                </span>
                                {isOpen
                                    ? <FiChevronDown size={13} color="#7c3aed" />
                                    : <FiChevronRight size={13} color="var(--text-muted)" />
                                }
                            </button>

                            {/* Sub-Items List */}
                            {isOpen && (
                                <div style={{ paddingLeft: 4, transition: 'all 0.2s ease' }}>
                                    {section.items.map(({ path, icon, label }) => (
                                        <NavLink
                                            key={path}
                                            to={path}
                                            style={({ isActive }) => ({
                                                display: 'flex', alignItems: 'center', gap: 10, padding: '7px 10px',
                                                borderRadius: 9, marginBottom: 1, textDecoration: 'none',
                                                background: isActive ? '#ede9fe' : 'transparent',
                                                color: isActive ? '#7c3aed' : 'var(--text-secondary)',
                                                fontWeight: isActive ? 600 : 400, fontSize: 13,
                                                transition: 'all 0.12s',
                                            })}
                                        >
                                            <span style={{ fontSize: 15 }}>{icon}</span>
                                            {label}
                                        </NavLink>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </nav>

            {/* Bottom Actions */}
            <div style={{ padding: '10px 14px', borderTop: '1px solid var(--border)', display: 'flex', gap: 8, flexShrink: 0 }}>
                <button
                    onClick={() => dispatch(toggleDarkMode())}
                    className="btn btn-ghost"
                    style={{ flex: 1, display: 'flex', justifyContent: 'center', padding: '7px' }}
                >
                    {darkMode ? <FiSun size={15} /> : <FiMoon size={15} />}
                </button>
                <button
                    onClick={handleLogout}
                    className="btn btn-ghost"
                    style={{ flex: 1, display: 'flex', justifyContent: 'center', padding: '7px', color: '#ef4444' }}
                >
                    <FiLogOut size={15} />
                </button>
            </div>
        </aside>
    );
}
